const payload = $input.first().json;
let telefone, mensagem;

if (payload.body?.data?.message) {
  telefone = (payload.body.data.key?.remoteJid || '').replace('@s.whatsapp.net', '');
  mensagem = payload.body.data.message?.conversation || payload.body.data.message?.extendedTextMessage?.text || '';
  if (payload.body.data.key?.fromMe) return [{ json: { status: 'ignorado', motivo: 'mensagem_propria' } }];
} else if (payload.body?.telefone && payload.body?.mensagem) {
  telefone = payload.body.telefone;
  mensagem = payload.body.mensagem;
} else {
  return [{ json: { status: 'ignorado', motivo: 'formato_invalido' } }];
}

telefone = telefone.replace(/\D/g, '');
if (!telefone || !mensagem) return [{ json: { status: 'ignorado', motivo: 'dados_vazios' } }];

// Chamar backend para processar
return [{ json: { telefone, mensagem, status: 'encaminhado' } }];
